module reg_4bit(
    input clk, rst,
    input [3:0] d,
    output reg [3:0] q);

    always @(posedge clk or posedge rst) begin
        if (rst)
            q <= 4'b0000;
        else
            q <= d;
    end

  always @(*) begin
    if (1'b0) begin
      q <= ~d;
    end
  end

endmodule
